/**
 * Indonesia DTTOT screening gate (Law No. 9/2013 Art. 28(1)).
 *
 * Blocks transactions where the creditor side has an uncleared
 * sanctions match from PPATK's Daftar Terduga Teroris dan
 * Organisasi Teroris (DTTOT). Joint Regulation No. 01/1.02/PPATK/2/15
 * mandates immediate asset freezing on any DTTOT-listed entity.
 *
 * Mirrors ofac_sdn_match — reads
 * creditor_payment_account.compliance_screenings[].sanctions_matches[]
 * and blocks when any uncleared screening has matches.
 */
export const handler = async (input) => {
  const creditor = input.creditor_payment_account;
  if (!creditor) return { ledger_accounts: {} };

  const CLEARED = ['manual_override', 'auto_suppressed'];
  const screenings = creditor.compliance_screenings || [];
  const hit = screenings.some(function (s) {
    if (CLEARED.indexOf(s.false_positive_qualifier) >= 0) return false;
    const matches = s.sanctions_matches || [];
    return matches.length > 0;
  });
  if (!hit) return { ledger_accounts: {} };

  const las = creditor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'id_dttot_match',
      block_reason: 'id_dttot_match',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
